1	// Static packaging artifact tests — no build tools required, no FUSE mount.
2	//
3	// Verifies that build.sh and PKGBUILD contain the structural elements that
4	// make the AppImage work at runtime: ORT library bundling, AppRun LD_LIBRARY_PATH,
5	// and the onnxruntime runtime dependency declaration.
6	
7	use std::fs;
