1	// Static tests asserting the distribution-proof transcript structure and
2	// verify-appimage.sh integrity — no FUSE mount, no VM required.
3	//
4	// Transcripts may carry any of three valid STATUS values:
5	//   STATUS: ok                    (full VM run succeeded)
6	//   STATUS: skipped:tools-missing (build host lacks linuxdeploy/appimagetool)
7	//   STATUS: pending VM run        (placeholder until VM run is executed in S06)
8	// All three are accepted here; only structural completeness is enforced.
9	
10	use std::fs;
11	use std::os::unix::fs::PermissionsExt;
12	use std::path::Path;
13	
14	fn project_root() -> std::path::PathBuf {
15	    Path::new(env!("CARGO_MANIFEST_DIR")).to_path_buf()
16	}
17	
18	fn read_file(rel: &str) -> String {
19	    let path = project_root().join(rel);
20	    fs::read_to_string(&path).unwrap_or_else(|e| panic!("cannot read {rel}: {e}"))
21	}
22	
23	const REQUIRED_FIELDS: &[&str] = &[
24	    "STATUS:",
25	    "DISTRO:",
26	    "KERNEL:",
27	    "SIZE_BYTES:",
28	    "SHA256:",
29	    "EXIT_CODE:",
30	    "VERSION_OUTPUT:",
31	];
32	
33	const VALID_STATUSES: &[&str] = &[
34	    "STATUS: ok",
35	    "STATUS: skipped:tools-missing",
36	    "STATUS: pending VM run",
37	];
38	
39	fn assert_transcript(rel: &str) {
40	    let content = read_file(rel);
41	    for field in REQUIRED_FIELDS {
42	        assert!(
43	            content.contains(field),
44	            "transcript {rel} is missing required field '{field}'"
45	        );
46	    }
47	    let has_valid_status = VALID_STATUSES.iter().any(|s| content.contains(s));
48	    assert!(
49	        has_valid_status,
50	        "transcript {rel} has no recognized STATUS line; accepted values: {:?}",
51	        VALID_STATUSES
52	    );
53	}
54	
55	#[test]
56	fn debian12_transcript_has_required_fields() {
57	    assert_transcript("docs/distribution-proofs/appimage/debian12/transcript.md");
58	}
59	
60	#[test]
61	fn fedora39_transcript_has_required_fields() {
62	    assert_transcript("docs/distribution-proofs/appimage/fedora39/transcript.md");
63	}
64	
65	#[test]
66	fn arch_transcript_has_required_fields() {
67	    assert_transcript("docs/distribution-proofs/appimage/arch/transcript.md");
68	}
