70	#[test]
71	fn verify_appimage_sh_exists_and_is_executable() {
72	    let path = project_root().join("scripts/verify-appimage.sh");
73	    assert!(
74	        path.exists(),
75	        "scripts/verify-appimage.sh must exist"
76	    );
77	    let meta = fs::metadata(&path).expect("cannot stat scripts/verify-appimage.sh");
78	    let mode = meta.permissions().mode();
79	    assert!(
80	        mode & 0o111 != 0,
81	        "scripts/verify-appimage.sh must be executable (mode={mode:#o})"
82	    );
83	}
84	
85	#[test]
86	fn verify_appimage_sh_contains_status_emitter() {
87	    let src = read_file("scripts/verify-appimage.sh");
88	    assert!(
89	        src.contains("STATUS:"),
90	        "scripts/verify-appimage.sh must contain a STATUS: line emitter"
91	    );
92	    // The script writes the structured transcript unconditionally — even on failure.
93	    assert!(
94	        src.contains("echo \"STATUS:"),
95	        "scripts/verify-appimage.sh must emit STATUS via echo"
96	    );
97	}
